#!/usr/bin/env dotnet
#:include *.cs
#:include Models/*.cs
#:exclude Scratch.cs

var person = new Person("Ada", "Lovelace");
Console.WriteLine(NameHelper.Transform(person));

static class NameHelper
{
    public static string Transform(Person person) =>
        $"{person.FirstName} {person.LastName}".ToUpperInvariant();
}

